//! Prefill-skip coordinator — the facade the serving forward (`model.rs`)
//! instantiates to skip prefill chunks via the certified amplituhedron replay.
//!
//! The diamantic rule's serving-side speed unlock is residency + skip-work: when
//! a near-prefix frozen volume is gate-admissible (`2·τ ≤ γ`), the whole prefill
//! chunk `[layer_lo, layer_hi)` is served from cache instead of recomputed. The
//! two primitives already exist —
//!   * [`AmplituhedronCache::replay_admissible_measured`] (the measured-τ gate), and
//!   * [`LipschitzChain::exit_station`] (the per-model chain from real weights) —
//! but a caller still has to own the cache + chain + per-model `(num_layers,
//! scale)` and thread them through every call. This coordinator bundles them so
//! the hot path reduces to `capture(...)` / `try_skip(...)`. The eventual
//! `model.rs` wire is then a 3-line isolated change, not τ-machinery scattered
//! through the forward.
//!
//! "Miss, not lie" is preserved end-to-end: every Lipschitz factor over-estimates
//! τ, so the gate can only force a spurious *recompute*, never serve a flipped
//! token.

use crate::amplituhedron::AmplituhedronCache;
use crate::amplituhedron_tau::{LipschitzChain, QuantScale};

/// Owns the replay cache + the per-model τ machinery for prefill-skip.
pub struct PrefillReplayCoordinator {
    cache: AmplituhedronCache,
    chain: LipschitzChain,
    num_layers: usize,
    scale: QuantScale,
    /// Prefill chunks served from cache (admitted replays). The headline win.
    chunks_skipped: u64,
    /// Total decoder layers NOT recomputed across all admitted replays
    /// (`Σ (layer_hi − layer_lo)`). `layers_skipped × per-layer cost ≈` the
    /// wall-clock prefill avoided — the diamantic rule's residency/skip-work
    /// payoff, made countable.
    layers_skipped: u64,
}

impl PrefillReplayCoordinator {
    /// Build a coordinator for a model with a per-model `chain` (see
    /// [`LipschitzChain::exit_station`]), depth `num_layers`, and fixed-point
    /// `scale`. The margin gate is enabled here — the coordinator is the explicit
    /// opt-in site (the bare cache still defaults OFF).
    pub fn new(chain: LipschitzChain, num_layers: usize, scale: QuantScale) -> Self {
        let mut cache = AmplituhedronCache::new();
        cache.set_margin_admit_enabled(true);
        Self { cache, chain, num_layers, scale, chunks_skipped: 0, layers_skipped: 0 }
    }

    /// Freeze a post-prefill volume (`tail_residual`, `kv_slab`) under its prefix
    /// key for later near-prefix replay.
    pub fn capture(
        &mut self,
        prefix_hash: u64,
        prefix_len: u32,
        layer_lo: u16,
        layer_hi: u16,
        tail_residual: Vec<f32>,
        kv_slab: Vec<f32>,
    ) {
        self.cache
            .capture(prefix_hash, prefix_len, layer_lo, layer_hi, tail_residual, kv_slab);
    }

    /// Try to skip the prefill chunk `[layer_lo, layer_hi)` by serving a
    /// certified near-prefix replay. Derives `(γ, τ)` from the live-vs-cached
    /// residual via the chain, applies the diamantic gate, and returns the
    /// `(tail_residual, kv_slab)` to splice in on an admit. `None` ⇒ compute the
    /// chunk (miss, not lie).
    pub fn try_skip(
        &mut self,
        prefix_hash: u64,
        prefix_len: u32,
        layer_lo: u16,
        layer_hi: u16,
        live_resid: &[f32],
        cached_resid: &[f32],
        live_runner_up_margin: f64,
    ) -> Option<(Vec<f32>, Vec<f32>)> {
        let served = self.cache.replay_admissible_measured(
            prefix_hash,
            prefix_len,
            layer_lo,
            layer_hi,
            live_resid,
            cached_resid,
            live_runner_up_margin,
            &self.chain,
            self.num_layers,
            self.scale,
        );
        if served.is_some() {
            self.chunks_skipped = self.chunks_skipped.saturating_add(1);
            self.layers_skipped = self
                .layers_skipped
                .saturating_add(u64::from(layer_hi.saturating_sub(layer_lo)));
        }
        served
    }

    /// `(chunks_skipped, layers_skipped)` — the prefill compute avoided by
    /// admitted replays. `layers_skipped` is the load-bearing speed metric:
    /// times the per-layer prefill cost, it is the wall-clock saved.
    pub fn savings_report(&self) -> (u64, u64) {
        (self.chunks_skipped, self.layers_skipped)
    }

    /// `(exact_hits, admitted_hits, misses, margin_refusals)`.
    pub fn admission_stats(&self) -> (u64, u64, u64, u64) {
        self.cache.admission_stats()
    }

    /// Borrow the underlying cache (eviction policy, capacity, etc.).
    pub fn cache(&self) -> &AmplituhedronCache {
        &self.cache
    }
    pub fn cache_mut(&mut self) -> &mut AmplituhedronCache {
        &mut self.cache
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::amplituhedron_tau::{HeadLipschitz, LayerLipschitz};

    /// Unit exit-station chain (logit Lipschitz = 1) so τ = ‖Δresid‖₂ directly.
    fn unit_chain() -> LipschitzChain {
        LipschitzChain {
            layer_bounds: vec![],
            head: HeadLipschitz { w_lm_row_2norm_max: 1.0, k_rms_bound: 1.0, softcap_lipschitz: 1.0 },
        }
    }

    /// Unit chain WITH per-block bounds (all 1.0) so mid-range replay also gives
    /// logit Lipschitz = 1 within the depth cap.
    fn unit_chain_bounded(num_layers: usize) -> LipschitzChain {
        unit_chain().with_layer_bounds((0..num_layers).map(|_| Some(LayerLipschitz(1.0))).collect())
    }

    #[test]
    fn coordinator_skips_small_drift_prefill_chunk() {
        let mut co = PrefillReplayCoordinator::new(unit_chain(), 1, QuantScale::DEFAULT);
        co.capture(0xCAFE, 256, 0, 1, vec![7.0; 4], vec![9.0; 8]);
        let live = vec![1.0f32, 0.0, 0.0, 0.0];
        // tiny drift (Δ = 0) under a healthy margin → admit → chunk skipped, and
        // we get the cached volume back to splice in.
        let got = co.try_skip(0xF00D, 256, 0, 1, &live, &live, 100.0);
        assert!(got.is_some(), "tiny residual drift ⇒ prefill chunk skipped");
        let (tail, kv) = got.unwrap();
        assert_eq!(tail[0], 7.0);
        assert_eq!(kv[0], 9.0);
        let (_exact, admitted, _miss, _ref) = co.admission_stats();
        assert_eq!(admitted, 1);
        // savings accounting: 1 chunk, (layer_hi 1 − layer_lo 0) = 1 layer skipped.
        assert_eq!(co.savings_report(), (1, 1));
    }

    #[test]
    fn coordinator_accumulates_layers_skipped_over_chunks() {
        let mut co = PrefillReplayCoordinator::new(unit_chain_bounded(8), 8, QuantScale::DEFAULT);
        let live = vec![1.0f32, 0.0, 0.0, 0.0];
        // Two captured chunks spanning layers [0,3) and [3,8) → 3 + 5 = 8 layers.
        co.capture(0xCAFE, 256, 0, 3, vec![7.0; 4], vec![9.0; 8]);
        co.capture(0xCAFE, 256, 3, 8, vec![7.0; 4], vec![9.0; 8]);
        assert!(co.try_skip(0xF00D, 256, 0, 3, &live, &live, 100.0).is_some());
        assert!(co.try_skip(0xF00D, 256, 3, 8, &live, &live, 100.0).is_some());
        assert_eq!(co.savings_report(), (2, 8), "2 chunks, 3+5 = 8 layers skipped");
    }

    #[test]
    fn coordinator_recomputes_large_drift_miss_not_lie() {
        let mut co = PrefillReplayCoordinator::new(unit_chain(), 1, QuantScale::DEFAULT);
        co.capture(0xCAFE, 256, 0, 1, vec![7.0; 4], vec![9.0; 8]);
        let live = vec![1.0f32, 0.0, 0.0, 0.0];
        let far = vec![1001.0f32, 0.0, 0.0, 0.0];
        // large drift → 2·τ > γ → miss → caller must recompute (never lie).
        assert!(
            co.try_skip(0xF00D, 256, 0, 1, &live, &far, 100.0).is_none(),
            "large residual drift ⇒ recompute, not a flipped serve"
        );
        let (_exact, admitted, miss, _ref) = co.admission_stats();
        assert_eq!(admitted, 0);
        assert!(miss >= 1);
        // a miss skips nothing — never bills phantom savings.
        assert_eq!(co.savings_report(), (0, 0));
    }
}
